// // This module decrements the counter on every positive edge of the clock and resets it to maximum value when the reset signal is asserted.
module binary_counter (
    input wire clk,
    input wire reset,
    output reg [3:0] count
);

always @(posedge clk) begin
    if (reset) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
